function initBilling(container, api, user) {
  api.get('/api/billing/status').then(function(r) {
    if (!r.ok) return;
    var info = container.querySelector('#billing-plan-info');
    if (r.data && r.data.plan) {
      info.querySelector('.plan-tier').textContent = r.data.plan;
      info.querySelector('.plan-desc').textContent = r.data.status === 'active' ? 'Your subscription is active.' : 'Manage your subscription below.';
    }
  });
  container.querySelector('#btn-manage-plan').onclick = function() {
    api.post('/api/billing/portal').then(function(r) {
      if (r.ok && r.data && r.data.url) window.open(r.data.url, '_blank');
    });
  };
  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok) return;
    var pk = '', tableId = '';
    (r.data || []).forEach(function(s) {
      if (s.key === 'stripe_publishable_key') pk = s.value || '';
      if (s.key === 'stripe_pricing_table_id') tableId = s.value || '';
    });
    if (pk && tableId) {
      var ct = container.querySelector('#stripe-pricing-container');
      ct.innerHTML = '<stripe-pricing-table pricing-table-id="' + tableId + '" publishable-key="' + pk + '"></stripe-pricing-table>';
      var sc = document.createElement('script'); sc.src = 'https://js.stripe.com/v3/pricing-table.js'; sc.async = true;
      document.head.appendChild(sc);
    }
  });
}

