function initTeam(container, api, user) {
  api.get('/api/users').then(function(r) {
    var tbody = container.querySelector('#team-tbody');
    var empty = container.querySelector('#team-empty');
    if (!r.ok || !r.data || r.data.length === 0) { empty.style.display = ''; tbody.parentElement.style.display = 'none'; return; }
    tbody.innerHTML = r.data.map(function(m) {
      return '<tr><td><div style="font-weight:500">' + (m.name || '-') + '</div><div style="font-size:12px;color:var(--t2)">' + m.email + '</div></td><td>' + (m.role_name || '-') + '</td><td><span class="badge ' + (m.status || 'active') + '">' + (m.status || 'active') + '</span></td><td>' + (m.last_login_at ? new Date(m.last_login_at).toLocaleDateString() : 'Never') + '</td><td></td></tr>';
    }).join('');
  });
  var modal = container.querySelector('#invite-modal');
  container.querySelector('#btn-invite-member').onclick = function() { modal.style.display = 'flex'; container.querySelector('#invite-email').value = ''; container.querySelector('#invite-email').focus(); };
  container.querySelector('#btn-cancel-invite').onclick = function() { modal.style.display = 'none'; };
