function initDashboardList(container, api, user) {
  var grid = container.querySelector('#dashboards-grid');
  var empty = container.querySelector('#dashboards-empty');
  var viewer = container.querySelector('#dashboard-viewer');
  var widgetArea = container.querySelector('#dashboard-widgets');
  var headerTitle = document.getElementById('header-center-title');
  var sidebar = document.getElementById('sidebar');

  // Load widgets
  function loadWidgets() {
    // Online members (simulated - would use websockets in production)
    var onlineEl = container.querySelector('#widget-online');
    var loginsEl = container.querySelector('#widget-logins');
    var totalEl = container.querySelector('#widget-total');
    var weatherEl = container.querySelector('#widget-weather');
    var uptimeEl = container.querySelector('#widget-uptime');

    // Animate counting up
    function animateCount(el, target, duration) {
      if (!el) return;
      var start = 0;
      var startTime = null;
      function step(ts) {
        if (!startTime) startTime = ts;
        var progress = Math.min((ts - startTime) / duration, 1);
        el.textContent = Math.floor(progress * target);
        if (progress < 1) requestAnimationFrame(step);
      }
      requestAnimationFrame(step);
    }

    // Fetch tenant stats
    api.get('/api/dashboards').then(function(r) {
      var count = r.ok && r.data ? r.data.length : 0;
      animateCount(totalEl, count, 800);
    });

    // Simulated real-time online count
    var onlineCount = Math.floor(Math.random() * 5) + 1;
    animateCount(onlineEl, onlineCount, 600);

    // Simulated login count today
    var loginCount = Math.floor(Math.random() * 12) + 3;
    animateCount(loginsEl, loginCount, 700);

    // Uptime
    if (uptimeEl) uptimeEl.textContent = '99.9%';

    // Weather widget
    if (weatherEl) {
      try {
        fetch('https://wttr.in/?format=%t+%C&m').then(function(r) { return r.text(); }).then(function(t) {
          weatherEl.textContent = t.trim() || '--';
        }).catch(function() { weatherEl.textContent = '--'; });
      } catch(e) { weatherEl.textContent = '--'; }
    }

    // Load custom widget tiles
    api.get('/api/dashboards').then(function(r) {
      if (!r.ok || !r.data) return;
      var customArea = container.querySelector('#dashboard-custom-widgets');
      if (!customArea) return;
      var widgets = (r.data || []).filter(function(d) { return d.status === 'active' && d.name && d.name.indexOf('[widget]') === 0; });
      if (!widgets.length) return;
      customArea.innerHTML = widgets.map(function(w, i) {
        return '<div class="dash-widget-custom" data-idx="' + i + '"><div style="padding:8px 12px;font-size:12px;color:var(--t2);border-bottom:1px solid var(--bdr)">' + w.name.replace('[widget] ','') + '</div><div class="widget-frame" data-id="' + w.id + '"></div></div>';
      }).join('');
      widgets.forEach(function(w, i) {
        var frame = customArea.querySelectorAll('.widget-frame')[i];
        if (!frame) return;
        api.post('/api/dashboards/' + w.id + '/render', {}).then(function(rr) {
          if (!rr.ok) return;
          var iframe = document.createElement('iframe');
          iframe.sandbox = 'allow-scripts allow-same-origin';
          iframe.style.cssText = 'width:100%;height:200px;border:none';
          frame.appendChild(iframe);
          var doc = iframe.contentDocument || iframe.contentWindow.document;
          doc.open();
          doc.write('<!DOCTYPE html><html><head><style>body{margin:0;font-family:system-ui,sans-serif;background:transparent;color:#f0f1f4}' + (rr.data.css||'') + '</style></head><body>' + (rr.data.html||'') + '<scr'+'ipt>' + (rr.data.js||'') + '</scr'+'ipt></body></html>');
          doc.close();
        });
      });
    });

    // Refresh online count every 30s
    setInterval(function() {
      onlineCount = Math.max(1, onlineCount + Math.floor(Math.random() * 3) - 1);
      if (onlineEl) onlineEl.textContent = onlineCount;
    }, 30000);
  }

  function exitViewer() {
    viewer.classList.remove('active');
    viewer.innerHTML = '';
    if (headerTitle) { headerTitle.style.display = 'none'; headerTitle.textContent = ''; }
    if (sidebar) sidebar.style.display = '';
    grid.style.display = '';
    if (widgetArea) widgetArea.style.display = '';
    if (!grid.children.length) empty.style.display = '';
  }

  function openDashboard(d) {
    grid.style.display = 'none';
    empty.style.display = 'none';
    if (widgetArea) widgetArea.style.display = 'none';
    if (sidebar) sidebar.style.display = 'none';
    if (headerTitle) { headerTitle.textContent = d.name; headerTitle.style.display = ''; }
    viewer.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--t3)">Loading...</div>';
    viewer.classList.add('active');

    api.post('/api/dashboards/' + d.id + '/render', {}).then(function(r) {
      if (!r.ok) {
        viewer.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--danger)">Failed to load dashboard.</div>';
        return;
      }
      var data = r.data;
      var html = data.html || '';
      var css = data.css || '';
      var js = data.js || '';
      var iframe = document.createElement('iframe');
      iframe.sandbox = 'allow-scripts allow-forms allow-popups allow-same-origin';
      viewer.innerHTML = '';
      viewer.appendChild(iframe);
      var doc = iframe.contentDocument || iframe.contentWindow.document;
      doc.open();
      doc.write('<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><style>body{margin:0;font-family:system-ui,-apple-system,sans-serif}' + css + '</style></head><body>' + html + '<scr' + 'ipt>' + js + '</scr' + 'ipt></body></html>');
      doc.close();
    }).catch(function() {
      viewer.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--danger)">Network error.</div>';
    });
  }

  window.addEventListener('hashchange', function handler() {
    if (viewer.classList.contains('active') && location.hash.replace('#','').split('?')[0] !== 'dashboard_list') {
      exitViewer();
      window.removeEventListener('hashchange', handler);
    }
  });

  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape' && viewer.classList.contains('active')) exitViewer();
  });

  api.get('/api/dashboards').then(function(r) {
    if (!r.ok || !r.data || r.data.length === 0) {
      empty.style.display = '';
      grid.style.display = 'none';
      return;
    }
    var dashboards = r.data.filter(function(d) { return d.status === 'active' && (!d.name || d.name.indexOf('[widget]') !== 0); });
    if (!dashboards.length) {
      empty.style.display = '';
      grid.style.display = 'none';
      return;
    }
    empty.style.display = 'none';
    grid.innerHTML = dashboards.map(function(d, i) {
      var imgHtml = d.tile_image_url
        ? '<div class="dash-card-img"><img src="' + d.tile_image_url + '" alt=""></div>'
        : '<div class="dash-card-img"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg></div>';
      var tooltip = d.last_viewed_at ? 'Last viewed: ' + new Date(d.last_viewed_at).toLocaleString() : 'Not yet viewed';
      return '<div class="dash-card" data-idx="' + i + '">'
        + '<div class="dash-card-tooltip">' + tooltip + '</div>'
        + imgHtml
        + '<div class="dash-card-body"><h3>' + d.name + '</h3><p>' + (d.description || '') + '</p></div>'
        + '</div>';
    }).join('');
    grid.querySelectorAll('.dash-card').forEach(function(card) {
      card.onclick = function() { openDashboard(dashboards[parseInt(this.dataset.idx)]); };
    });
  });

  loadWidgets();
}

