function initAdminTenants(container, api, user) {
  var modal = container.querySelector('#tenant-modal');
  var planModal = container.querySelector('#plan-modal');
  var notesModal = container.querySelector('#notes-modal');
  var currentPlanTenantId = null;
  var currentNotesTenantId = null;

  function loadTenants() {
    api.get('/api/admin/tenants').then(function(r) {
      if (!r.ok) return;
      var tenants = r.data.data || r.data || [];
      container.querySelector('#tenants-tbody').innerHTML = tenants.map(function(t) {
        return '<tr data-id="' + t.id + '" data-name="' + t.name + '" data-plan="' + (t.plan || 'free') + '">'
          + '<td><strong>' + t.name + '</strong></td>'
          + '<td><code>' + t.slug + '</code></td>'
          + '<td>' + (t.owner_email || '-') + '</td>'
          + '<td>' + (t.member_count || 0) + '</td>'
          + '<td><span class="plan-link" data-id="' + t.id + '" data-name="' + t.name + '" data-plan="' + (t.plan || 'free') + '" style="color:var(--acc);cursor:pointer">' + (t.plan || 'free') + '</span></td>'
          + '<td>' + new Date(t.created_at).toLocaleDateString() + '</td>'
          + '</tr>';
      }).join('');

      // Click on plan link opens plan modal
      container.querySelectorAll('.plan-link').forEach(function(link) {
        link.onclick = function(e) {
          e.stopPropagation();
          currentPlanTenantId = this.getAttribute('data-id');
          container.querySelector('#plan-tenant-name').value = this.getAttribute('data-name');
          container.querySelector('#plan-tier').value = this.getAttribute('data-plan') || 'free';
          container.querySelector('#plan-dash-limit').value = '';
          planModal.style.display = 'flex';
        };
      });

      // Click on row opens notes
      container.querySelectorAll('tr[data-id]').forEach(function(row) {
        row.onclick = function() {
          openNotes(this.dataset.id, this.dataset.name);
        };
      });
    });
  }

  function openNotes(tenantId, tenantName) {
    currentNotesTenantId = tenantId;
    container.querySelector('#notes-tenant-name').textContent = tenantName;
    container.querySelector('#note-input').value = '';
    notesModal.style.display = 'flex';
    loadNotes();
  }

  function loadNotes() {
    if (!currentNotesTenantId) return;
    api.get('/api/admin/tenants/' + currentNotesTenantId + '/notes').then(function(r) {
      var list = container.querySelector('#notes-list');
      if (!r.ok || !r.data || !r.data.length) {
        list.innerHTML = '<div style="text-align:center;color:var(--t3);padding:20px">No notes yet.</div>';
        return;
      }
      list.innerHTML = r.data.map(function(n) {
        return '<div class="note-item" data-note-id="' + n.id + '">'
          + '<div class="note-meta"><span>' + (n.author_name || n.author_email || 'Admin') + ' &middot; ' + new Date(n.created_at).toLocaleString() + (n.updated_at !== n.created_at ? ' (edited)' : '') + '</span>'
          + '<div class="note-actions"><button class="note-edit">Edit</button><button class="note-del">Delete</button></div></div>'
          + '<div class="note-content">' + escHtml(n.content) + '</div></div>';
      }).join('');

      list.querySelectorAll('.note-edit').forEach(function(btn) {
        btn.onclick = function() {
          var item = this.closest('.note-item');
          var noteId = item.dataset.noteId;
          var contentEl = item.querySelector('.note-content');
          var cur = contentEl.textContent;
          var newVal = prompt('Edit note:', cur);
          if (newVal !== null && newVal !== cur) {
            api.patch('/api/admin/tenants/' + currentNotesTenantId + '/notes/' + noteId, { content: newVal }).then(function(r) {
              if (r.ok) loadNotes();
            });
          }
        };
      });

      list.querySelectorAll('.note-del').forEach(function(btn) {
        btn.onclick = function() {
          var noteId = this.closest('.note-item').dataset.noteId;
          if (confirm('Delete this note?')) {
            api.delete('/api/admin/tenants/' + currentNotesTenantId + '/notes/' + noteId).then(function(r) {
              if (r.ok) loadNotes();
            });
          }
        };
      });
    });
  }

  function escHtml(s) { var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  // Add note
  container.querySelector('#btn-add-note').onclick = function() {
    var input = container.querySelector('#note-input');
    var content = input.value.trim();
    if (!content) return;
    api.post('/api/admin/tenants/' + currentNotesTenantId + '/notes', { content: content }).then(function(r) {
      if (r.ok) { input.value = ''; loadNotes(); }
    });
  };

  // Close notes modal
  container.querySelector('#btn-close-notes').onclick = function() { notesModal.style.display = 'none'; };

  // Create tenant modal
  container.querySelector('#btn-create-tenant').onclick = function() {
    modal.style.display = 'flex';
    container.querySelector('#tenant-name').value = '';
    container.querySelector('#tenant-slug').value = '';
    container.querySelector('#tenant-name').focus();
  };
  container.querySelector('#btn-close-tenant-modal').onclick = function() { modal.style.display = 'none'; };
  container.querySelector('#btn-cancel-tenant').onclick = function() { modal.style.display = 'none'; };
  container.querySelector('#tenant-name').oninput = function() {
    container.querySelector('#tenant-slug').value = this.value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
  };
  ['tenant-name', 'tenant-slug'].forEach(function(id) {
    container.querySelector('#' + id).onkeydown = function(e) { if (e.key === 'Enter') container.querySelector('#btn-submit-tenant').click(); };
  });
  container.querySelector('#btn-submit-tenant').onclick = function() {
    var name = container.querySelector('#tenant-name').value.trim();
    var slug = container.querySelector('#tenant-slug').value.trim();
    if (!name || !slug) { alert('Name and slug are required.'); return; }
    var btn = this; btn.disabled = true;
    api.post('/api/admin/tenants', { name: name, slug: slug }).then(function(r) {
      btn.disabled = false;
      if (!r.ok) { alert(r.error ? r.error.message : 'Failed to create tenant'); return; }
      modal.style.display = 'none';
      loadTenants();
    });
  };

  // Plan modal
  container.querySelector('#btn-close-plan-modal').onclick = function() { planModal.style.display = 'none'; };
  container.querySelector('#btn-cancel-plan').onclick = function() { planModal.style.display = 'none'; };
  container.querySelector('#btn-submit-plan').onclick = function() {
    if (!currentPlanTenantId) return;
    var body = { planTier: container.querySelector('#plan-tier').value };
    var dl = container.querySelector('#plan-dash-limit').value;
    if (dl !== '') body.dashboardLimit = parseInt(dl, 10);
    var btn = this; btn.disabled = true;
    api.patch('/api/admin/tenants/' + currentPlanTenantId + '/plan', body).then(function(r) {
      btn.disabled = false;
      if (!r.ok) { alert(r.error ? r.error.message : 'Failed to update plan'); return; }
      planModal.style.display = 'none';
      loadTenants();
    });
  };

  loadTenants();
}

