function initAdminDashboards(container, api, user) {
  var allItems = [];
  var searchEl = container.querySelector('#dash-search');
  var filterEl = container.querySelector('#dash-filter-status');
  var sortEl = container.querySelector('#dash-sort');
  var tbody = container.querySelector('#admin-dash-tbody');

  function render() {
    var q = searchEl.value.toLowerCase();
    var filterStatus = filterEl.value;
    var sort = sortEl.value;
    var items = allItems.filter(function(d) {
      if (filterStatus && d.status !== filterStatus) return false;
      if (q && d.name.toLowerCase().indexOf(q) === -1 && (d.tenant_name || '').toLowerCase().indexOf(q) === -1 && (d.description || '').toLowerCase().indexOf(q) === -1) return false;
      return true;
    });
    items.sort(function(a, b) {
      if (sort === 'name_asc') return a.name.localeCompare(b.name);
      if (sort === 'name_desc') return b.name.localeCompare(a.name);
      if (sort === 'updated_desc') return new Date(b.updated_at || 0) - new Date(a.updated_at || 0);
      if (sort === 'viewed_desc') return new Date(b.last_viewed_at || 0) - new Date(a.last_viewed_at || 0);
      if (sort === 'created_asc') return new Date(a.created_at) - new Date(b.created_at);
      return new Date(b.created_at) - new Date(a.created_at);
    });
    if (!items.length) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:var(--t2);padding:40px">' + (allItems.length ? 'No matching dashboards.' : 'No dashboards created yet.') + '</td></tr>';
      return;
    }
    tbody.innerHTML = items.map(function(d) {
      var statusCls = 'status-' + (d.status || 'draft');
      var connIcon = d.fetch_url ? '<span style="color:var(--acc)">&#x2713; Connected</span>' : '<span style="color:var(--t3)">-</span>';
      var edited = d.updated_at ? new Date(d.updated_at).toLocaleDateString() : '-';
      var viewed = d.last_viewed_at ? new Date(d.last_viewed_at).toLocaleDateString() + ' ' + new Date(d.last_viewed_at).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : '-';
      return '<tr data-id="' + d.id + '">'
        + '<td><strong>' + d.name + '</strong>' + (d.description ? '<br><small style="color:var(--t3)">' + d.description + '</small>' : '') + '</td>'
        + '<td>' + (d.tenant_name || '-') + (d.owner_email ? '<br><small style="color:var(--t3)">' + d.owner_email + '</small>' : '') + '</td>'
        + '<td>' + connIcon + '</td>'
        + '<td><span class="status-badge ' + statusCls + '">' + (d.status || 'draft') + '</span></td>'
        + '<td>' + edited + '</td>'
        + '<td>' + viewed + '</td>'
        + '<td>' + new Date(d.created_at).toLocaleDateString() + '</td>'
        + '</tr>';
    }).join('');
    tbody.querySelectorAll('tr[data-id]').forEach(function(row) {
      row.onclick = function() { location.hash = 'admin_builder?edit=' + this.dataset.id; };
    });
  }

  searchEl.oninput = render;
  filterEl.onchange = render;
  sortEl.onchange = render;

  api.get('/api/admin/dashboards?limit=100').then(function(r) {
    if (!r.ok) return;
    allItems = r.data.data || r.data || [];
    render();
  });
}

