function initAdminEmail(container, api, user) {
  // ─── SMTP Settings ───
  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok) return;
    (r.data || []).forEach(function(s) {
      var map = { smtp_host: '#email-smtp-host', smtp_port: '#email-smtp-port', smtp_user: '#email-smtp-user', smtp_from: '#email-from', smtp_encryption: '#email-encryption' };
      if (map[s.key]) { var el = container.querySelector(map[s.key]); if (el) el.value = s.value || ''; }
      if (s.key === 'smtp_pass' && s.value) { var pe = container.querySelector('#email-smtp-pass'); if (pe) pe.placeholder = 'Configured (enter new to change)'; }
    });
  });
  container.querySelector('#btn-save-email').onclick = function() {
    var updates = {};
    var fields = { smtp_host: '#email-smtp-host', smtp_port: '#email-smtp-port', smtp_user: '#email-smtp-user', smtp_from: '#email-from', smtp_encryption: '#email-encryption', smtp_pass: '#email-smtp-pass' };
    for (var k in fields) { var v = container.querySelector(fields[k]).value.trim(); if (v) updates[k] = v; }
    if (Object.keys(updates).length === 0) return;
    var btn = this; btn.disabled = true;
    api.patch('/api/admin/settings', updates).then(function(r) {
      btn.disabled = false;
      if (r.ok) { btn.textContent = 'Saved!'; setTimeout(function() { btn.textContent = 'Save'; }, 2000); }
    });
  };
  container.querySelector('#btn-test-email').onclick = function() {
    var btn = this; btn.disabled = true; btn.textContent = 'Sending...';
    api.post('/api/admin/email/test', { to: user.email }).then(function(r) {
      btn.disabled = false;
      btn.textContent = r.ok ? 'Sent!' : 'Failed';
      setTimeout(function() { btn.textContent = 'Send test'; }, 3000);
    });
  };

  // ─── Email Templates ───
  var tplList = container.querySelector('#email-tpl-list');
  var overlay = container.querySelector('#tpl-editor-overlay');
  var editingKey = null;

  function loadTemplates() {
    api.get('/api/admin/email-templates').then(function(r) {
      if (!r.ok || !r.data) return;
      tplList.innerHTML = r.data.map(function(t) {
        var updated = t.updated_at ? new Date(t.updated_at).toLocaleDateString() : '-';
        return '<div class="tpl-item" data-key="' + t.template_key + '">'
          + '<div class="tpl-item-info"><h4>' + t.template_key.replace(/_/g, ' ') + '</h4><p>' + (t.description || t.subject) + '</p></div>'
          + '<div class="tpl-item-meta">Updated: ' + updated + '<br>Vars: ' + (t.variables || []).join(', ') + '</div>'
          + '</div>';
      }).join('');
      tplList.querySelectorAll('.tpl-item').forEach(function(el) {
        el.onclick = function() { openEditor(el.dataset.key); };
      });
    });
  }

  function openEditor(key) {
    editingKey = key;
    container.querySelector('#tpl-editor-title').textContent = 'Edit: ' + key.replace(/_/g, ' ');
    container.querySelector('#tpl-key').value = key;
    // Fetch full template
    api.get('/api/admin/email-templates/' + key).then(function(r) {
      if (!r.ok || !r.data) return;
      var t = r.data;
      container.querySelector('#tpl-desc').value = t.description || '';
      container.querySelector('#tpl-subject').value = t.subject || '';
      container.querySelector('#tpl-body-html').value = t.body_html || '';
      container.querySelector('#tpl-body-text').value = t.body_text || '';
      // Variables
      var vars = t.variables || [];
      container.querySelector('#tpl-vars').innerHTML = vars.map(function(v) {
        return '<span class="tpl-var-tag" data-var="' + v + '">{{' + v + '}}</span>';
      }).join('');
      container.querySelectorAll('.tpl-var-tag').forEach(function(tag) {
        tag.onclick = function() {
          // Insert variable at cursor in focused textarea
          var focused = document.activeElement;
          if (focused && (focused.id === 'tpl-body-html' || focused.id === 'tpl-body-text' || focused.id === 'tpl-subject')) {
            var start = focused.selectionStart;
            var end = focused.selectionEnd;
            var val = focused.value;
            var insert = '{{' + tag.dataset.var + '}}';
            focused.value = val.substring(0, start) + insert + val.substring(end);
            focused.selectionStart = focused.selectionEnd = start + insert.length;
            focused.focus();
          }
        };
      });
      updatePreview();
      overlay.style.display = '';
    });
  }

  function updatePreview() {
    var html = container.querySelector('#tpl-body-html').value;
    var previewDiv = container.querySelector('#tpl-preview');
    // Replace variables with sample values for preview
    var sampleVars = { name: 'John Doe', code: '123456', link: '#', verify_url: '#', invite_url: '#', recovery_url: '#', platform_name: 'XRay BI', tenant_name: 'Acme Corp', inviter_name: 'Admin', email: 'john@example.com' };
    var rendered = html;
    for (var k in sampleVars) {
      rendered = rendered.replace(new RegExp('\\{\\{' + k + '\\}\\}', 'g'), sampleVars[k]);
    }
    var iframe = document.createElement('iframe');
    iframe.style.cssText = 'width:100%;height:300px;border:none';
    previewDiv.innerHTML = '';
    previewDiv.appendChild(iframe);
    var doc = iframe.contentDocument || iframe.contentWindow.document;
    doc.open();
    doc.write('<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{margin:12px;font-family:system-ui,sans-serif;font-size:14px;color:#333}</style></head><body>' + rendered + '</body></html>');
    doc.close();
  }

  // Debounced preview update
  var previewTimer;
  function schedulePreview() {
    clearTimeout(previewTimer);
    previewTimer = setTimeout(updatePreview, 500);
  }

  container.querySelector('#tpl-body-html').oninput = schedulePreview;
  container.querySelector('#tpl-editor-close').onclick = function() { overlay.style.display = 'none'; };
  container.querySelector('#tpl-cancel-btn').onclick = function() { overlay.style.display = 'none'; };

  container.querySelector('#tpl-save-btn').onclick = function() {
    if (!editingKey) return;
    var btn = this; btn.disabled = true;
    api.patch('/api/admin/email-templates/' + editingKey, {
      subject: container.querySelector('#tpl-subject').value,
      bodyHtml: container.querySelector('#tpl-body-html').value,
      bodyText: container.querySelector('#tpl-body-text').value
    }).then(function(r) {
      btn.disabled = false;
      if (r.ok) {
        btn.textContent = 'Saved!';
        setTimeout(function() { btn.textContent = 'Save template'; }, 2000);
        loadTemplates();
      }
    });
  };

  container.querySelector('#tpl-test-btn').onclick = function() {
    if (!editingKey) return;
    var btn = this; btn.disabled = true; btn.textContent = 'Sending...';
    api.post('/api/admin/email-templates/' + editingKey + '/test', {}).then(function(r) {
      btn.disabled = false;
      btn.textContent = r.ok ? 'Sent!' : 'Failed';
      setTimeout(function() { btn.textContent = 'Send test'; }, 3000);
    });
  };

  loadTemplates();
}

